import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';
import 'profile_screen.dart';

class WhoILikeScreen extends StatefulWidget {
  final Function(int) onSwitchTab;

  const WhoILikeScreen({super.key, required this.onSwitchTab});

  @override
  State<WhoILikeScreen> createState() => _WhoILikeScreenState();
}

class _WhoILikeScreenState extends State<WhoILikeScreen> {
  static const _bg = Color(0xFF0E0E0E);
  static const _surface = Color(0xFF1A1A1A);
  static const _baseUrl = 'http://10.0.2.2:8000';

  bool _isLoading = true;
  String? _error;
  List<Map<String, dynamic>> _likes = [];

  // Unique colour per rank — cycles after 12
  static const _rankColors = [
    Color(0xFFFFC107), //  1 - amber
    Color(0xFFFF5722), //  2 - deep orange
    Color(0xFFE91E8C), //  3 - pink
    Color(0xFF00BCD4), //  4 - cyan
    Color(0xFF8BC34A), //  5 - light green
    Color(0xFF9C27B0), //  6 - purple
    Color(0xFF03A9F4), //  7 - light blue
    Color(0xFFFF9800), //  8 - orange
    Color(0xFF4CAF50), //  9 - green
    Color(0xFFF44336), // 10 - red
    Color(0xFF00E5FF), // 11 - cyan accent
    Color(0xFFCDDC39), // 12 - lime
  ];

  Color _rankColor(int rank) {
    return _rankColors[(rank - 1) % _rankColors.length];
  }

  @override
  void initState() {
    super.initState();
    _loadLikes();
  }

  Future<String?> _getToken() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString('jwt_token');
  }

  Future<void> _loadLikes() async {
    setState(() { _isLoading = true; _error = null; });
    try {
      final token = await _getToken();
      final response = await http.get(
        Uri.parse('$_baseUrl/api/who_i_like'),
        headers: {'Authorization': 'Bearer $token'},
      );
      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        setState(() {
          _likes = (data['users'] as List<dynamic>).cast<Map<String, dynamic>>();
          _isLoading = false;
        });
      } else {
        setState(() { _error = 'Failed (${response.statusCode})'; _isLoading = false; });
      }
    } catch (e) {
      setState(() { _error = 'Error: $e'; _isLoading = false; });
    }
  }

  Future<void> _pushRerank() async {
    try {
      final token = await _getToken();
      final rankings = _likes.asMap().entries.map((e) {
        return {'username': e.value['username'], 'rank': e.key + 1};
      }).toList();
      await http.put(
        Uri.parse('$_baseUrl/api/like/rerank'),
        headers: {'Authorization': 'Bearer $token', 'Content-Type': 'application/json'},
        body: jsonEncode({'rankings': rankings}),
      );
    } catch (_) {}
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: _bg,
      appBar: AppBar(
        backgroundColor: _bg,
        elevation: 0,
        centerTitle: true,
        title: const Column(
          children: [
            Text(
              'WHO I LIKE',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.bold,
                fontSize: 16,
                letterSpacing: 1.2,
              ),
            ),
            Text(
              'Slide up to prioritise your likes',
              style: TextStyle(color: Colors.white38, fontSize: 11),
            ),
          ],
        ),
        actions: [
          IconButton(
            icon: const Icon(Icons.refresh, color: Colors.white54),
            onPressed: _loadLikes,
          ),
        ],
      ),
      body: _buildBody(),
    );
  }

  Widget _buildBody() {
    if (_isLoading) {
      return const Center(child: CircularProgressIndicator(color: Color(0xFFFFC107)));
    }
    if (_error != null) {
      return Center(child: Text(_error!, style: const TextStyle(color: Colors.redAccent)));
    }
    if (_likes.isEmpty) {
      return RefreshIndicator(
        onRefresh: _loadLikes,
        color: const Color(0xFFFFC107),
        child: ListView(children: [
          const SizedBox(height: 200),
          Center(
            child: Column(children: [
              const Icon(Icons.favorite_border, size: 64, color: Color(0xFFFFC107)),
              const SizedBox(height: 16),
              const Text('No likes yet', style: TextStyle(color: Colors.white70, fontSize: 16)),
              const SizedBox(height: 24),
              ElevatedButton(
                onPressed: () => widget.onSwitchTab(0),
                style: ElevatedButton.styleFrom(backgroundColor: const Color(0xFFFFC107), foregroundColor: Colors.black),
                child: const Text('Go to Search'),
              ),
            ]),
          ),
        ]),
      );
    }

    return RefreshIndicator(
      onRefresh: _loadLikes,
      color: const Color(0xFFFFC107),
      child: ReorderableListView.builder(
        padding: const EdgeInsets.only(top: 8, bottom: 80),
        itemCount: _likes.length,
        onReorder: (oldIndex, newIndex) {
          setState(() {
            if (newIndex > oldIndex) newIndex--;
            final item = _likes.removeAt(oldIndex);
            _likes.insert(newIndex, item);
          });
          _pushRerank();
        },
        itemBuilder: (context, index) {
          final user = _likes[index];
          final rank = index + 1;
          final int userId = user['id'] as int? ?? 0;
          final String username = user['username'] as String? ?? '';
          final int? age = user['age'] as int?;
          final String? sex = user['sex'] as String?;
          final String photoUrl = '$_baseUrl/api/users/$userId/photo';

          return _WhoILikeTile(
            key: ValueKey(userId),
            rank: rank,
            index: index,
            userId: userId,
            username: username,
            age: age,
            sex: sex,
            photoUrl: photoUrl,
            rankColor: _rankColor(rank),
            onTap: () => Navigator.push(
              context,
              MaterialPageRoute(builder: (_) => ProfileScreen(
                userId: userId, username: username,
                age: age ?? 0, sex: sex ?? '', photoUrl: photoUrl,
              )),
            ),
          );
        },
      ),
    );
  }
}

class _WhoILikeTile extends StatelessWidget {
  final int rank;
  final int index;
  final int userId;
  final String username;
  final int? age;
  final String? sex;
  final String photoUrl;
  final Color rankColor;
  final VoidCallback onTap;

  const _WhoILikeTile({
    super.key,
    required this.rank,
    required this.index,
    required this.userId,
    required this.username,
    required this.age,
    required this.sex,
    required this.photoUrl,
    required this.rankColor,
    required this.onTap,
  });

  @override
  Widget build(BuildContext context) {
    return ReorderableDragStartListener(
      index: index,
      child: GestureDetector(
      onTap: onTap,
      child: Container(
        margin: const EdgeInsets.symmetric(horizontal: 0, vertical: 1),
        color: const Color(0xFF0E0E0E),
        child: Column(
          children: [
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
              child: Row(
                children: [
                  // Rank number
                  SizedBox(
                    width: 36,
                    child: Text(
                      '$rank',
                      style: TextStyle(
                        color: rankColor,
                        fontSize: 28,
                        fontWeight: FontWeight.bold,
                      ),
                    ),
                  ),
                  const SizedBox(width: 12),
                  // Avatar
                  CircleAvatar(
                    radius: 24,
                    backgroundColor: Colors.white12,
                    child: ClipOval(
                      child: Image.network(
                        photoUrl,
                        width: 48,
                        height: 48,
                        fit: BoxFit.cover,
                        errorBuilder: (_, __, ___) => Text(
                          username.isNotEmpty ? username[0].toUpperCase() : '?',
                          style: const TextStyle(color: Colors.white, fontSize: 18, fontWeight: FontWeight.bold),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 14),
                  // Name + info
                  Expanded(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          username,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 16,
                            fontWeight: FontWeight.w600,
                          ),
