import 'package:flutter/material.dart';
import 'package:stream_chat_flutter/stream_chat_flutter.dart';

class ChatScreen extends StatefulWidget {
  final String matchUsername;
  final String currentUsername;
  final String streamToken;
  final String apiKey;

  const ChatScreen({
    super.key,
    required this.matchUsername,
    required this.currentUsername,
    required this.streamToken,
    required this.apiKey,
  });

  @override
  State<ChatScreen> createState() => _ChatScreenState();
}

class _ChatScreenState extends State<ChatScreen> {
  StreamChatClient? _client;
  Channel? _channel;
  bool _isLoading = true;
  String? _error;

  @override
  void initState() {
    super.initState();
    _initChat();
  }

  Future<void> _initChat() async {
    try {
      final client = StreamChatClient(widget.apiKey, logLevel: Level.OFF);

      await client.connectUser(
        User(id: widget.currentUsername),
        widget.streamToken,
      );

      // Channel id is sorted so both sides get the same channel
      final names = [widget.currentUsername, widget.matchUsername]..sort();
      final channelId = names.join('-');

      final channel = client.channel('messaging', id: channelId, extraData: {
        'members': [widget.currentUsername, widget.matchUsername],
      });
      await channel.watch();

      setState(() {
        _client = client;
        _channel = channel;
        _isLoading = false;
      });
    } catch (e) {
      setState(() { _error = 'Chat error: $e'; _isLoading = false; });
    }
  }

  @override
  void dispose() {
    _client?.disconnectUser();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    if (_isLoading) {
      return Scaffold(
        backgroundColor: const Color(0xFF0E0E0E),
        appBar: AppBar(
          backgroundColor: const Color(0xFF0E0E0E),
          title: Text(widget.matchUsername),
        ),
        body: const Center(child: CircularProgressIndicator(color: Colors.greenAccent)),
      );
    }

    if (_error != null) {
      return Scaffold(
        backgroundColor: const Color(0xFF0E0E0E),
        appBar: AppBar(
          backgroundColor: const Color(0xFF0E0E0E),
          title: Text(widget.matchUsername),
        ),
        body: Center(
          child: Text(_error!, style: const TextStyle(color: Colors.redAccent)),
        ),
      );
    }

    return StreamChat(
      client: _client!,
      streamChatThemeData: StreamChatThemeData.dark().copyWith(
        colorTheme: StreamColorTheme.dark().copyWith(
          appBg: const Color(0xFF0E0E0E),
          barsBg: const Color(0xFF1A1A1A),
        ),
        messageInputTheme: const StreamMessageInputThemeData(
          inputBackgroundColor: Color(0xFF1A1A1A),
        ),
      ),
      child: StreamChannel(
        channel: _channel!,
        child: Scaffold(
          backgroundColor: const Color(0xFF0E0E0E),
          appBar: AppBar(
            backgroundColor: const Color(0xFF1A1A1A),
            elevation: 0,
            title: Text(
              widget.matchUsername,
              style: const TextStyle(color: Colors.white, fontWeight: FontWeight.w600),
            ),
            iconTheme: const IconThemeData(color: Colors.white),
          ),
          body: const Column(
            children: [
              Expanded(child: StreamMessageListView()),
              StreamMessageInput(),
            ],
          ),
        ),
      ),
    );
  }
}

